// ─────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
store.albums   = store.albums   || {};

const now = Date.now();
for (const [k,v] of Object.entries(store.albums))   { if (!v?.expiresAt || v.expiresAt < now) delete store.albums[k]; }
for (const [k,v] of Object.entries(store.sessions)) { if (!v?.updatedAt || now - v.updatedAt > 86400000) delete store.sessions[k]; }

function txt(item)  { return (item.json.message?.text || item.json.message?.caption || '').trim(); }
function low(item)  { return txt(item).toLowerCase(); }

function extractTicket(value) {
  const m = String(value||'').match(/\b\d+\b/);
  return m ? m[0] : '';
}

function mapStatus(value) {
  const v = String(value||'').trim().toLowerCase();
  const map = {
    '1':1,'novo':1,'new':1,
    '2':2,'em atendimento':2,'atribuido':2,'atribuído':2,
    '3':3,'planejado':3,'planned':3,
    '4':4,'pendente':4,'pending':4,
    '5':5,'solucionado':5,'resolvido':5,'solved':5,
    '6':6,'fechado':6,'closed':6
  };
  return map[v] || null;
}

function mapPriority(value) {
  const v = String(value||'').trim().toLowerCase();
  const map = {
    '1':1,'agendamento':1,
    '2':2,'normal 48h':2,'normal 48 horas':2,'normal':2,
    '3':3,'solucionar':3,
    '4':4,'alerta':4,
    '5':5,'retorno/serv. rápido':5,'retorno':5,'servico rapido':5,'serviço rápido':5,
    '6':6,'urgente':6
  };
  return map[v] || null;
}

function proxDiasUteis(qtd) {
  const TZ_OFFSET = -3 * 60;
  const agora = new Date(now + TZ_OFFSET * 60000);
  const hojeLocal = new Date(agora.toISOString().slice(0,10) + 'T00:00:00.000Z');
  const hojeDow = hojeLocal.getUTCDay();
  const horaLocal = agora.getUTCHours() + agora.getUTCMinutes()/60;
  const ehSabado = hojeDow === 6;
  const aposDeadlineSabado = ehSabado && horaLocal >= 12;

  const dias = [];
  let cursor = new Date(hojeLocal);
  cursor.setUTCDate(cursor.getUTCDate() + 1);

  while (dias.length < qtd) {
    const dow = cursor.getUTCDay();
    if (dow === 0) { cursor.setUTCDate(cursor.getUTCDate() + 1); continue; }
    if (dow === 6 && aposDeadlineSabado) { cursor.setUTCDate(cursor.getUTCDate() + 1); continue; }
    dias.push(new Date(cursor));
    cursor.setUTCDate(cursor.getUTCDate() + 1);
  }
  return dias;
}

function formatBR(d) {
  const dd = String(d.getUTCDate()).padStart(2,'0');
  const mm = String(d.getUTCMonth()+1).padStart(2,'0');
  const yyyy = d.getUTCFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

function dowLabel(d) {
  const nomes = ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'];
  return nomes[d.getUTCDay()];
}

function toGLPIDate(brDate, hora) {
  const [dd,mm,yyyy] = brDate.split('/');
  const horaStr = hora.includes(':') ? hora : hora + ':00:00';
  const [hh,min,ss] = horaStr.split(':').map(Number);
  return `${yyyy}-${mm}-${dd} ${String(hh).padStart(2,'0')}:${String(min).padStart(2,'0')}:${String(ss||0).padStart(2,'0')}`;
}

// Teclado fixo sempre visível
const menuKeyboard = {
  keyboard: [
    [{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]
  ],
  resize_keyboard: true,
  one_time_keyboard: false
};

// Monta reply_markup com botões de opção (inline como linhas do Reply Keyboard)
function opcoesTeclado(opcoes, comMenu) {
  // Monta linhas de botões — até 2 por linha
  const rows = [];
  for (let i = 0; i < opcoes.length; i += 2) {
    const row = [{ text: opcoes[i] }];
    if (opcoes[i+1]) row.push({ text: opcoes[i+1] });
    rows.push(row);
  }
  if (comMenu !== false) rows.push([{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]);
  return { keyboard: rows, resize_keyboard: true, one_time_keyboard: true };
}

function menuText() {
  return [
    '🤖 *Menu GLPI*',
    '',
    'Escolha uma opção:'
  ].join('\n');
}

function menuMarkup() {
  return {
    keyboard: [
      [{ text: '1️⃣ Abrir chamado' }, { text: '2️⃣ Ver chamado' }],
      [{ text: '3️⃣ Mudar status'  }, { text: '4️⃣ Fechar chamado' }],
      [{ text: '5️⃣ Enviar mídia'  }, { text: '6️⃣ Comentar chamado' }],
      [{ text: '7️⃣ Foto/Vídeo + Solucionar' }]
    ],
    resize_keyboard: true,
    one_time_keyboard: true
  };
}

// Normaliza texto dos botões do menu para os mesmos comandos
function normalizarMenu(t) {
  const map = {
    '1️⃣ abrir chamado':          '1',
    '2️⃣ ver chamado':             '2',
    '3️⃣ mudar status':            '3',
    '4️⃣ fechar chamado':          '4',
    '5️⃣ enviar mídia':            '5',
    '6️⃣ comentar chamado':        '6',
    '7️⃣ foto/vídeo + solucionar': '7',
    '🏠 menu':                    '/menu',
    '❌ cancelar':                '/cancelar'
  };
  return map[t.toLowerCase()] || t.toLowerCase();
}

// ─────────────────────────────────────────────
// LOOP PRINCIPAL
// ─────────────────────────────────────────────
return items.map((item) => {
  const message   = item.json.message || {};
  const chatId    = String(message.chat?.id || '');
  const userText  = txt(item);
  const userTextN = normalizarMenu(userText);
  const isPhoto   = Array.isArray(message.photo) && message.photo.length > 0;
  const isVideo   = !!message.video || !!message.video_note;
  const isMedia   = isPhoto || isVideo;
  const mediaGroupId = message.media_group_id ? String(message.media_group_id) : '';
  const session   = store.sessions[chatId] || { state:'idle', data:{}, updatedAt:now };

  function save(state, data) { store.sessions[chatId] = { state, data: data||{}, updatedAt:now }; }
  function clear()           { delete store.sessions[chatId]; }

  function reply(text, markup) {
    return { json: {
      ...item.json,
      action: 'reply',
      chat_id: chatId,
      reply_text: text,
      reply_markup: markup || menuKeyboard
    }};
  }

  if (!chatId) return { json:{ ...item.json, action:'ignore', reply_text:'', chat_id:'' } };

  // ── Comandos globais ──
  if (['/start','/menu','menu', '🏠 menu'].includes(userTextN)) {
    save('idle',{});
    return reply(menuText(), menuMarkup());
  }
  if (['/cancelar','cancelar','❌ cancelar'].includes(userTextN)) {
    clear();
    return reply('✅ Operação cancelada.\n\nEscolha uma opção:', menuMarkup());
  }
  if (['/fim','fim'].includes(userTextN)) {
    if (session.state === 'photo_mode') { clear(); return reply('📷 Modo foto encerrado.\n\nEscolha uma opção:', menuMarkup()); }
    return reply('Não havia modo foto ativo.\n\nEscolha uma opção:', menuMarkup());
  }

  // Atalhos diretos
  const mFoto = userTextN.match(/^\/foto\s+(\d+)$/) || userTextN.match(/^\/midia\s+(\d+)$/);
  if (mFoto) { save('photo_mode',{ticket_id:mFoto[1]}); return reply(`📷 Modo foto ativado para chamado *#${mFoto[1]}*.\nEnvie as fotos. Pressione *❌ Cancelar* para sair.`); }

  const mVer = userTextN.match(/^\/ver\s+(\d+)$/);
  if (mVer)  { clear(); return { json:{ ...item.json, action:'view_ticket', chat_id:chatId, ticket_id:mVer[1] } }; }

  // ════════════════════════════════════════════
  const st = session.state;
  const sd = session.data || {};

  // ── IDLE ──
  if (st === 'idle') {
    const v = userTextN;
    if (['1','abrir chamado','/abrir'].includes(v)) {
      save('open_await_title',{});
      return reply('📝 *Abrir chamado*\n\nInforme o *título* do chamado:');
    }
    if (['2','ver chamado','/ver'].includes(v)) {
      save('await_view_ticket',{});
      return reply('🔍 Informe o *número* do chamado:');
    }
    if (['3','mudar status','/status'].includes(v)) {
      save('await_status_ticket',{});
      return reply('🔄 Informe o *número* do chamado para alterar o status:');
    }
    if (['4','fechar chamado','/fechar'].includes(v)) {
      save('await_close_ticket',{});
      return reply('✅ Informe o *número* do chamado para fechar:');
    }
    if (['5','enviar mídia','/midia','/foto'].includes(v)) {
      save('await_photo_ticket',{});
      return reply('📷🎥 Informe o *número* do chamado para anexar foto ou vídeo:');
    }
    if (['6','comentar chamado','/comentar'].includes(v)) {
      save('await_comment_ticket',{});
      return reply('💬 Informe o *número* do chamado para adicionar comentário:');
    }
    if (['7','foto/vídeo + solucionar','/fotosolucionar'].includes(v)) {
      save('await_photosolve_ticket',{});
      return reply('📷🎥 Informe o *número* do chamado para enviar mídia e solucionar:');
    }
  }

  // ════════════════════════════════════════════
  // FLUXO ABRIR CHAMADO
  // ════════════════════════════════════════════

  if (st === 'open_await_title') {
    save('open_await_client_search', { title: userText });
    return reply('🏢 Informe o nome do *cliente* para buscar:');
  }

  if (st === 'open_await_client_search') {
    save('open_await_client_choice', { ...sd, client_search: userText });
    return { json: { ...item.json, action:'search_entity', chat_id:chatId, search_term:userText, session_data: JSON.stringify({...sd, client_search:userText}) } };
  }

  if (st === 'open_await_client_choice') {
    const idx = parseInt(userText,10);
    const opts = sd.entity_options || [];
    // Aceita tanto número quanto o texto do botão "1 - Nome"
    const idxByText = opts.findIndex(o => userText.toLowerCase().includes(o.name.toLowerCase()));
    const finalIdx = (!isNaN(idx) && idx >= 1 && idx <= opts.length) ? idx - 1 : idxByText;
    if (finalIdx < 0) return reply(`❌ Opção inválida. Toque em um dos botões ou digite o número.`);
    const chosen = opts[finalIdx];
    save('open_await_description', { ...sd, entity_id: chosen.id, entity_name: chosen.name });
    return reply(`✅ Cliente: *${chosen.name}*\n\n✍️ Informe a *descrição* do chamado:`);
  }

  if (st === 'open_await_description') {
    save('open_await_priority', { ...sd, content: userText });
    return reply(
      '⚡ Escolha a *prioridade*:',
      opcoesTeclado(['1 - Agendamento','2 - Normal 48h','3 - Solucionar','4 - Alerta','5 - Retorno/Serv. Rápido','6 - Urgente'])
    );
  }

  if (st === 'open_await_priority') {
    // Aceita "4 - Alta" ou "4" ou "alta"
    const pText = userText.split(' - ')[0].trim();
    const p = mapPriority(pText) || mapPriority(userText);
    if (!p) return reply('❌ Prioridade inválida. Toque em um dos botões.',
      opcoesTeclado(['1 - Agendamento','2 - Normal 48h','3 - Solucionar','4 - Alerta','5 - Retorno/Serv. Rápido','6 - Urgente'])
    );
    save('open_await_serial', { ...sd, priority: p });
    return reply('🔢 Informe o *Serial* do equipamento, ou toque em *Pular*:',
      opcoesTeclado(['Pular'])
    );
  }

  if (st === 'open_await_serial') {
    const serial = (userText.toLowerCase() === 'pular' || userText === '0') ? '' : userText;
    // Lista de técnicos - SUBSTITUIR PELOS DADOS DA SUA EQUIPE
    const tecnicos = [
      { id: 1, name: 'Técnico 1' },
      { id: 2, name: 'Técnico 2' },
      { id: 3, name: 'Técnico 3' },
      { id: 4, name: 'Técnico 4' },
      { id: 5, name: 'Técnico 5' },
      { id: 6, name: 'Técnico 6' }
    ];
    const rows = tecnicos.map(t => [{ text: t.name }]);
    rows.push([{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]);
    const markup = { keyboard: rows, resize_keyboard: true, one_time_keyboard: true };
    save('open_await_tech_choice', { ...sd, serial, user_options: tecnicos });
    return reply('👨‍💻 Escolha o *técnico* responsável:', markup);
  }

  if (st === 'open_await_tech_choice') {
    const opts = sd.user_options || [];
    const idx = parseInt(userText,10);
    // Aceita o nome do botão (ex: "Djeyson") ou número
    const idxByName = opts.findIndex(o => o.name.toLowerCase() === userText.toLowerCase());
    const finalIdx = (idxByName >= 0) ? idxByName
                   : (!isNaN(idx) && idx >= 1 && idx <= opts.length) ? idx - 1 : -1;
    if (finalIdx < 0) return reply(`❌ Opção inválida. Toque em um dos botões.`);
    const chosen = opts[finalIdx];
    const dias = proxDiasUteis(3);
    const btnDatas = dias.map(d => `${dowLabel(d)} ${formatBR(d)}`);
    save('open_await_start_date', { ...sd, tech_id: chosen.id, tech_name: chosen.name, start_date_options: dias.map(d=>formatBR(d)) });
    return reply('📅 Escolha a *data de criação*:', opcoesTeclado(btnDatas));
  }

  if (st === 'open_await_start_date') {
    const opts = sd.start_date_options || [];
    // Tenta achar pelo botão "Seg 21/04/2025" ou pelo número
    let finalIdx = -1;
    const idx = parseInt(userText,10);
    if (!isNaN(idx) && idx >= 1 && idx <= opts.length) {
      finalIdx = idx - 1;
    } else {
      finalIdx = opts.findIndex(d => userText.includes(d));
    }
    if (finalIdx < 0) return reply('❌ Opção inválida. Toque em um dos botões.',
      opcoesTeclado((sd.start_date_options||[]).map((d,i) => { const dias = proxDiasUteis(3); return `${dowLabel(dias[i])} ${d}`; }))
    );
    const chosenDate = opts[finalIdx];
    const dias = proxDiasUteis(3);
    const btnDatas = dias.map(d => `${dowLabel(d)} ${formatBR(d)}`);
    save('open_await_due_date', { ...sd, start_date: chosenDate, due_date_options: dias.map(d=>formatBR(d)) });
    return reply('⏰ Escolha a *data limite*:', opcoesTeclado(btnDatas));
  }

  if (st === 'open_await_due_date') {
    const opts = sd.due_date_options || [];
    let finalIdx = -1;
    const idx = parseInt(userText,10);
    if (!isNaN(idx) && idx >= 1 && idx <= opts.length) {
      finalIdx = idx - 1;
    } else {
      finalIdx = opts.findIndex(d => userText.includes(d));
    }
    if (finalIdx < 0) return reply('❌ Opção inválida. Toque em um dos botões.');
    const chosenDue = opts[finalIdx];
    clear();
    return {
      json: {
        ...item.json,
        action:         'create_ticket',
        chat_id:        chatId,
        ticket_title:   sd.title,
        ticket_content: sd.content,
        entity_id:      sd.entity_id,
        priority:       sd.priority,
        serial:         sd.serial || '',
        tech_id:        sd.tech_id,
        start_date:     toGLPIDate(sd.start_date, '08:00:00'),
        due_date:       toGLPIDate(chosenDue,     '17:00:00')
      }
    };
  }

  // ════════════════════════════════════════════
  // FLUXO VER CHAMADO
  // ════════════════════════════════════════════
  if (st === 'await_view_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Digite apenas o número, ex: 1234');
    clear();
    return { json:{ ...item.json, action:'view_ticket', chat_id:chatId, ticket_id:tid } };
  }

  // ════════════════════════════════════════════
  // FLUXO MUDAR STATUS
  // ════════════════════════════════════════════
  if (st === 'await_status_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Ex: 1234');
    save('await_status_value', { ticket_id:tid });
    return reply(
      `Escolha o novo status do chamado *#${tid}*:`,
      opcoesTeclado(['1 - Novo','2 - Em atendimento','3 - Planejado','4 - Pendente','5 - Resolvido','6 - Fechado'])
    );
  }

  if (st === 'await_status_value') {
    const pText = userText.split(' - ')[0].trim();
    const code  = mapStatus(pText) || mapStatus(userText);
    const tid   = sd.ticket_id || '';
    if (!code) return reply('❌ Status inválido. Toque em um dos botões.',
      opcoesTeclado(['1 - Novo','2 - Em atendimento','3 - Planejado','4 - Pendente','5 - Resolvido','6 - Fechado'])
    );
    clear();
    if (code === 6) {
      save('await_close_solution', { ticket_id:tid, from_status:true });
      return reply(`🧾 Informe o texto de solução para fechar o chamado *#${tid}*:`);
    }
    return { json:{ ...item.json, action:'update_status', chat_id:chatId, ticket_id:tid, new_status:code } };
  }

  // ════════════════════════════════════════════
  // FLUXO FECHAR CHAMADO
  // ════════════════════════════════════════════
  if (st === 'await_close_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Ex: 1234');
    save('await_close_solution', { ticket_id:tid });
    return reply(`🧾 Informe o texto de solução para fechar o chamado *#${tid}*:`);
  }

  if (st === 'await_close_solution') {
    const tid = sd.ticket_id || '';
    clear();
    return { json:{ ...item.json, action:'close_ticket', chat_id:chatId, ticket_id:tid, solution_text:userText } };
  }

  // ════════════════════════════════════════════
  // FLUXO COMENTAR CHAMADO
  // ════════════════════════════════════════════
  if (st === 'await_comment_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Ex: 1234');
    save('await_comment_text', { ticket_id: tid });
    return reply(`💬 Escreva o *comentário* para o chamado *#${tid}*:`);
  }

  if (st === 'await_comment_text') {
    const tid = sd.ticket_id || '';
    clear();
    return { json:{ ...item.json, action:'add_comment', chat_id:chatId, ticket_id:tid, comment_text:userText } };
  }

  // ════════════════════════════════════════════
  // FLUXO FOTO/VÍDEO + SOLUCIONAR
  // ════════════════════════════════════════════
  if (st === 'await_photosolve_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Ex: 1234');
    save('photosolve_await_media', { ticket_id: tid });
    return reply(`📷🎥 Envie a *foto ou vídeo* do chamado *#${tid}*:`);
  }

  if (st === 'photosolve_await_media') {
    if (!isMedia) return reply('❌ Por favor envie uma foto ou vídeo.');
    let file_id, file_type, file_unique_id;
    if (isPhoto) {
      const best = message.photo[message.photo.length - 1];
      file_id = best.file_id; file_unique_id = best.file_unique_id || ''; file_type = 'photo';
    } else {
      const vid = message.video || message.video_note;
      file_id = vid.file_id; file_unique_id = vid.file_unique_id || ''; file_type = 'video';
    }
    if (mediaGroupId) store.albums[mediaGroupId] = { ticket_id: sd.ticket_id, expiresAt: now + 600000 };
    save('photosolve_await_solution', { ...sd, file_id, file_unique_id, file_type, media_group_id: mediaGroupId });
    return reply(`✅ Mídia recebida!\n\n🧾 Agora escreva o texto de *solução* do chamado *#${sd.ticket_id}*:`);
  }

  if (st === 'photosolve_await_solution') {
    const tid = sd.ticket_id || '';
    clear();
    return {
      json: {
        ...item.json,
        action:         'photosolve',
        chat_id:        chatId,
        ticket_id:      tid,
        file_id:        sd.file_id,
        file_unique_id: sd.file_unique_id,
        file_type:      sd.file_type,
        media_group_id: sd.media_group_id || '',
        solution_text:  userText
      }
    };
  }

  if (st === 'await_photo_ticket') {
    const tid = extractTicket(userText);
    if (!tid) return reply('❌ Número inválido. Ex: 1234');
    save('photo_mode', { ticket_id:tid });
    return reply(`📷 Modo foto ativado para chamado *#${tid}*.\nEnvie as fotos. Pressione *❌ Cancelar* para sair.`);
  }

  if (isMedia) {
    // Se está no fluxo photosolve_await_media, o bloco acima já tratou
    let tid = '';
    if (mediaGroupId && store.albums[mediaGroupId]?.ticket_id) tid = String(store.albums[mediaGroupId].ticket_id);
    if (!tid) tid = extractTicket(userText);
    if (!tid && (st === 'photo_mode') && sd.ticket_id) tid = String(sd.ticket_id);
    if (!tid) return reply('📷🎥 Recebi a mídia, mas não sei em qual chamado anexar.\nUse /foto 1234 ou menu > 5️⃣ Enviar mídia.');
    if (mediaGroupId) store.albums[mediaGroupId] = { ticket_id:tid, expiresAt: now + 600000 };
    let file_id, file_unique_id, file_type;
    if (isPhoto) {
      const best = message.photo[message.photo.length - 1];
      file_id = best.file_id; file_unique_id = best.file_unique_id || ''; file_type = 'photo';
    } else {
      const vid = message.video || message.video_note;
      file_id = vid.file_id; file_unique_id = vid.file_unique_id || ''; file_type = 'video';
    }
    return { json:{ ...item.json, action:'upload_media', chat_id:chatId, ticket_id:tid, file_id, file_unique_id, file_type, media_group_id:mediaGroupId } };
  }

  // fallback
  return reply(menuText(), menuMarkup());
});

const store = $getWorkflowStaticData('global');
const ctx    = $('Merge Contexto + Sessão').first().json;
const chatId = ctx.chat_id;
let sd;
try { sd = JSON.parse(ctx.session_data || '{}'); } catch(e) { sd = {}; }

const results = items[0].json;
const raw  = results.data || results;
const list = Array.isArray(raw) ? raw : [];

const menuKeyboard = { keyboard: [[{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]], resize_keyboard: true, one_time_keyboard: false };

if (!list.length) {
  store.sessions[chatId] = { state:'open_await_client_search', data:{ title: sd.title }, updatedAt: Date.now() };
  return [{ json:{ chat_id:chatId, reply_text:'❌ Nenhum cliente encontrado para "' + sd.client_search + '".\nTente outro trecho do nome:', reply_markup: menuKeyboard } }];
}

const opts = list.slice(0,9).map(e => {
  const id   = e['1'] ?? e.id;
  const name = (e['14'] && String(e['14']) !== String(id)) ? e['14']
             : (e['9']  && String(e['9'])  !== String(id)) ? e['9'] : null;
  return { id, name };
}).filter(o => o.name);

if (!opts.length) {
  store.sessions[chatId] = { state:'open_await_client_search', data:{ title: sd.title }, updatedAt: Date.now() };
  return [{ json:{ chat_id:chatId, reply_text:'❌ Nenhum cliente encontrado.\nTente outro trecho do nome:', reply_markup: menuKeyboard } }];
}

// Monta botões — 1 por linha para caber o nome completo
const rows = opts.map((o,i) => [{ text: `${i+1} - ${o.name}` }]);
rows.push([{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]);
const markup = { keyboard: rows, resize_keyboard: true, one_time_keyboard: true };

store.sessions[chatId] = {
  state: 'open_await_client_choice',
  data:  { ...sd, entity_options: opts },
  updatedAt: Date.now()
};

return [{ json:{ chat_id:chatId, reply_text:'🏢 *Clientes encontrados:*\n\nToque no nome do cliente:', parse_mode:'Markdown', reply_markup: markup } }];

