const ctx = $('Merge Contexto + Sessão').first().json;
return items.map(item => {
  const t = item.json;
  const statusMap = {1:'🆕 Novo',2:'🔧 Em atendimento',3:'📅 Planejado',4:'⏳ Pendente',5:'✅ Resolvido',6:'🔒 Fechado'};
  const prioMap   = {1:'🔵 Muito baixa',2:'🟢 Baixa',3:'🟡 Média',4:'🟠 Alta',5:'🔴 Muito alta',6:'⚫ Crítico'};
  const content   = (t.content||'-').replace(/<[^>]+>/g,'').substring(0,300);
  const date      = t.date_creation ? new Date(t.date_creation).toLocaleString('pt-BR') : '-';
  const due       = t.time_to_resolve ? new Date(t.time_to_resolve).toLocaleString('pt-BR') : '-';
  const reply = [
    `📋 *Chamado #${t.id}*`,
    `📌 Status: ${statusMap[t.status]||t.status}`,
    `⚡ Prioridade: ${prioMap[t.priority]||t.priority}`,
    `📝 Título: ${t.name||'-'}`,
    `📅 Aberto em: ${date}`,
    `⏰ Prazo: ${due}`,
    `🔢 Serial: ${t.externalid||'-'}`,
    `📄 Descrição:\n${content}`
  ].join('\n');
  return { json:{ chat_id:ctx.chat_id, reply_text:reply, parse_mode:'Markdown', reply_markup: { keyboard: [[{ text: '🏠 Menu' }, { text: '❌ Cancelar' }]], resize_keyboard: true, one_time_keyboard: false } } };
});

